import React, { useEffect, useRef, useState } from 'react';
import { toCanvas } from 'qrcode';
import './QRCode.css';

const QRCodePage = () => {
  const canvasRef = useRef(null);
  const [tableNumber, setTableNumber] = useState('1');
  const menuUrl = `${window.location.origin}/menu/${tableNumber}`;

  useEffect(() => {
    if (canvasRef.current) {
      toCanvas(canvasRef.current, menuUrl, {
        width: 256,
        margin: 1,
        color: {
          dark: '#000000',
          light: '#FFFFFF'
        }
      });
    }
  }, [menuUrl, tableNumber]);

  const handleDownload = () => {
    const canvas = canvasRef.current;
    if (canvas) {
      const link = document.createElement('a');
      link.download = `table-${tableNumber}-qr.png`;
      link.href = canvas.toDataURL();
      link.click();
    }
  };

  return (
    <div className="qrcode-page">
      <div className="page-header">
        <h1>📱 QR Code Menu Generator</h1>
        <p>Generate table-specific QR codes for customers</p>
      </div>

      <div className="qr-container">
        <div className="qr-wrapper">
          <canvas ref={canvasRef} style={{ width: '256px', height: '256px' }} />
          <div className="qr-info">
            <p><strong>Table:</strong> {tableNumber}</p>
            <p><strong>URL:</strong> {menuUrl}</p>
            <p>Print & place on table {tableNumber}</p>
          </div>
        </div>

        <div className="table-input-qr">
          <label>Table Number: </label>
          <input 
            type="text" 
            value={tableNumber}
            onChange={(e) => setTableNumber(e.target.value || '1')}
            placeholder="e.g. 1, 2, A1"
            maxLength="10"
          />
        </div>

        <div className="qr-actions">
          <button className="btn-download" onClick={handleDownload}>
            💾 Download QR PNG
          </button>
          <a href={menuUrl} target="_blank" rel="noopener noreferrer" className="btn-test">
            🔗 Test Customer Menu
          </a>
        </div>
      </div>

      <div className="qr-demo">
        <h3>How it works:</h3>
        <p>1. Enter table number → Generate QR<br/>2. Print & place on table<br/>3. Customer scans → sees menu + orders for that table (no login)</p>
      </div>
    </div>
  );
};

export default QRCodePage;
